package com.agrios.platform.tasks.api;
import com.agrios.platform.tasks.domain.RecurringTaskScheduleEntity; import jakarta.validation.constraints.*; import java.time.Instant; import java.util.UUID;
public final class RecurringTaskDtos {private RecurringTaskDtos(){} public record CreateRequest(@NotBlank String ownerContext,@NotNull UUID ownerEntityId,UUID cropCycleId,@NotBlank String taskType,@NotBlank @Size(max=240) String title,String description,@NotBlank String priority,UUID assignedTo,@Pattern(regexp="DAILY|WEEKLY|MONTHLY") String recurrenceType,@Min(1) int intervalValue,@NotNull Instant startAt,Instant endAt){} public record Response(UUID id,String recurrenceType,int intervalValue,Instant nextRunAt,Instant endAt,boolean active,long version){public static Response from(RecurringTaskScheduleEntity v){return new Response(v.id(),v.recurrenceType(),v.intervalValue(),v.nextRunAt(),v.endAt(),v.active(),v.version());}}}
